class CustomSkinService {
    static _instance;
    skinsPath = 'public/skins';
    skinsBaseUrl = '/skins';
    skins = [];
    static createInstance() {
        if (!this._instance) {
            this._instance = new CustomSkinService();
        }
    }
    static get instance() {
        this.createInstance();
        return this._instance;
    }
    async initialize() {
        await this.scanSkins();
    }
    async scanSkins() {
        if (!external_fs_.existsSync(this.skinsPath)) {
            console.log('CustomSkins path not found, ignore.');
            return;
        }
        const files = await external_fs_.promises.readdir(this.skinsPath);
        const skins = [];
        for (const skinDir of files) {
            if (!external_fs_.statSync(`${this.skinsPath}/${skinDir}`).isDirectory()) {
                continue;
            }
            const manifestPath = `${this.skinsPath}/${skinDir}/skin.json`;
            if (!external_fs_.existsSync(manifestPath)) {
                continue;
            }
            const manifestContent = await external_fs_.promises.readFile(manifestPath, { encoding: 'utf-8' });
            let manifest = JSON.parse(manifestContent);
            try {
                manifest = CustomSkinManifestSchema.parse(manifest);
            }
            catch (error) {
                if (error instanceof lib.z.ZodError) {
                    console.error(`Invalid manifest for skin ${skinDir}:`, error.errors);
                    continue;
                }
                else {
                    console.error(`Error parsing manifest for skin ${skinDir}:`, error);
                    continue;
                }
            }
            let skinIndexUrl = `${this.skinsBaseUrl}/${skinDir}/${manifest.main}`;
            skins.push({
                ...manifest,
                url: skinIndexUrl,
            });
        }
        this.skins = skins;
    }
}

