class PulsePlayList {
    mode = 'single';
    pulseIds = [];
    currentIndex = 0;
    changeInterval = 0;
    nextChangeTime = 0;
    constructor(pulseIds, mode = 'single', interval) {
        this.pulseIds = pulseIds;
        this.mode = mode;
        if (pulseIds.length <= 1) {
            mode = 'single';
        }
        if (mode !== 'single') {
            this.changeInterval = interval || 60;
            this.nextChangeTime = Date.now() + this.changeInterval * 1000;
        }
        if (mode === 'random') {
            this.suffle();
        }
    }
    getCurrentPulseId() {
        if (this.mode === 'single') {
            return this.pulseIds[0];
        }
        if (Date.now() > this.nextChangeTime) {
            this.nextChangeTime = Date.now() + this.changeInterval * 1000;
            this.currentIndex++;
            if (this.currentIndex >= this.pulseIds.length) { // ж’ӯж”ҫе®ҢжҜ•пјҢйҮҚж–°ејҖе§Ӣ
                this.currentIndex = 0;
                if (this.mode === 'random') { // йҡҸжңәж’ӯж”ҫж—¶йҮҚж–°жҙ—зүҢ
                    this.suffle();
                }
            }
        }
        return this.pulseIds[this.currentIndex];
    }
    suffle() {
        this.pulseIds = this.pulseIds.sort(() => Math.random() - 0.5);
    }
}

