class CoyoteGameManager {
    static _instance;
    games;
    events = new ExEventEmitter();
    /**
     * зј“еӯҳжёёжҲҸй…ҚзҪ®дҝЎжҒҜпјҢз”ЁдәҺеңЁж–ӯзәҝйҮҚиҝһж—¶жҒўеӨҚжёёжҲҸзҠ¶жҖҒ
     */
    configCache = new LRUCache({
        max: 1000,
        ttl: 1000 * 60 * 30, // 30 minutes
    });
    constructor() {
        this.games = new Map();
        DGLabWSManager.instance.on('clientConnected', (client) => this.handleCoyoteClientConnected(client));
    }
    static createInstance() {
        if (!this._instance) {
            this._instance = new CoyoteGameManager();
        }
    }
    static get instance() {
        this.createInstance();
        return this._instance;
    }
    async handleCoyoteClientConnected(client) {
        try {
            const game = await this.getOrCreateGame(client.clientId);
            await game.bindClient(client);
        }
        catch (error) {
            console.error('Failed to create game:', error);
        }
    }
    async createGame(clientId) {
        const game = new CoyoteGameController(clientId);
        await game.initialize();
        game.once('close', () => {
            this.games.delete(clientId);
        });
        this.games.set(clientId, game);
        return game;
    }
    getGame(clientId) {
        return this.games.get(clientId);
    }
    async getOrCreateGame(clientId) {
        let game = this.getGame(clientId);
        if (!game) {
            game = await this.createGame(clientId);
        }
        return game;
    }
    getGameList() {
        return this.games.values();
    }
    on = this.events.on.bind(this.events);
    once = this.events.once.bind(this.events);
    off = this.events.off.bind(this.events);
    removeAllListeners = this.events.removeAllListeners.bind(this.events);
}
CoyoteGameManager.createInstance();

