    /**
     * еӨ„зҗҶж ҮеҮҶMCPеҲқе§ӢеҢ–
     */
    static async handleInitialize(params) {
        const { protocolVersion, capabilities, clientInfo } = InitializeRequestParamsSchema.parse(params);
        // ж”ҜжҢҒзҡ„еҚҸи®®зүҲжң¬
        const supportedVersions = ["2025-03-26", "2025-06-18"];
        let negotiatedVersion = protocolVersion;
        // еҰӮжһңе®ўжҲ·з«ҜзүҲжң¬дёҚж”ҜжҢҒпјҢдҪҝз”ЁжҲ‘д»¬ж”ҜжҢҒзҡ„жңҖж–°зүҲжң¬
        if (!supportedVersions.includes(protocolVersion)) {
            negotiatedVersion = supportedVersions[0];
        }
        return {
            protocolVersion: negotiatedVersion,
            capabilities: {
                tools: {
                    listChanged: false
                },
                resources: {
                    subscribe: true,
                    listChanged: true
                },
                logging: {}
            },
            serverInfo: {
                name: "coyote-game-hub-mcp-server",
                title: "Coyote Game Hub MCP Server",
                version: "2.0.0"
            },
            instructions: "иҝҷжҳҜдёҖдёӘз”ЁдәҺжҺ§еҲ¶DG-Labз”өеҮ»жёёжҲҸзҡ„MCPжңҚеҠЎеҷЁгҖӮдҪҝз”Ёtools/listжҹҘзңӢеҸҜз”Ёе·Ҙе…·пјҢдҪҝз”Ёtools/callи°ғз”ЁжёёжҲҸжҺ§еҲ¶еҠҹиғҪгҖӮдҪҝз”Ёresources/listжҹҘзңӢеҸҜз”Ёиө„жәҗпјҲеҰӮеҪ“еүҚз”өйҮҸзҠ¶жҖҒпјүгҖӮ"
        };
    }
