    /**
     * еӨ„зҗҶе·Ҙе…·и°ғз”ЁиҜ·жұӮ
     */
    static async handleToolsCall(session, params) {
        const { name, arguments: args = {} } = ToolsCallParamsSchema.parse(params);
        try {
            let result;
            switch (name) {
                case "connect_game":
                    result = await this.handleConnectGame(session, { gameId: args.gameId });
                    break;
                case "disconnect_game":
                    result = await this.handleDisconnectGame(session);
                    break;
                case "get_game_status":
                    result = await this.handleGetGameStatus(session, {});
                    break;
                case "set_strength":
                    result = await this.handleSetStrength(session, { strength: args.strength });
                    break;
                case "increase_strength":
                    result = await this.handleIncreaseStrength(session, { amount: args.amount });
                    break;
                case "decrease_strength":
                    result = await this.handleDecreaseStrength(session, { amount: args.amount });
                    break;
                case "set_pulse":
                    result = await this.handleSetPulse(session, { pulseId: args.pulseId });
                    break;
                case "fire_action":
                    result = await this.handleFireAction(session, {
                        strength: args.strength,
                        duration: args.duration,
                        pulseId: args.pulseId
                    });
                    break;
                case "get_pulse_list":
                    result = await this.handleGetPulseList(session, {});
                    break;
                case "get_resources_list":
                    result = await this.handleResourcesList(session);
                    break;
                case "get_resource":
                    result = await this.handleResourcesRead(session, {
                        uri: args.uri
                    });
                    break;
                default:
                    throw {
                        code: MCP_ERROR_CODES.METHOD_NOT_FOUND,
                        message: `е·Ҙе…· '${name}' дёҚеӯҳеңЁ`
                    };
            }
            return {
                content: [
                    {
                        type: "text",
                        text: JSON.stringify(result, null, 2)
                    }
                ]
            };
        }
        catch (error) {
            return {
                content: [
                    {
                        type: "text",
                        text: `й”ҷиҜҜ: ${error.message || error}`
                    }
                ],
                isError: true
            };
        }
    }
    /**
     * еӨ„зҗҶиө„жәҗеҲ—иЎЁиҜ·жұӮ
     */
    static async handleResourcesList(session) {
        const resources = [
            {
                uri: `game://strength`,
                name: `еҪ“еүҚз”өйҮҸзҠ¶жҖҒ`,
                description: "е®һж—¶з”өйҮҸдҝЎжҒҜпјҢеҢ…жӢ¬еҪ“еүҚејәеәҰгҖҒејәеәҰйҷҗеҲ¶е’ҢйҡҸжңәејәеәҰиҢғеӣҙ",
                mimeType: "application/json"
            }
        ];
        return { resources };
    }
    /**
     * еӨ„зҗҶиө„жәҗиҜ»еҸ–иҜ·жұӮ
     */
    static async handleResourcesRead(session, params) {
        const { uri } = ResourcesReadParamsSchema.parse(params);
        if (uri === `game://strength`) {
            const validation = this.validateGame(session.gameId);
            if (!validation.valid) {
                throw validation.error;
            }
            const game = validation.game;
            const strengthInfo = {
                gameId: session.gameId,
                currentStrength: game?.strengthConfig?.strength || 0,
                strengthLimit: 200,
                randomStrength: game?.strengthConfig?.randomStrength || 0,
                isConnected: !!game?.client,
                isStarted: !!game?.running,
                lastUpdated: new Date().toISOString()
            };
            return {
                contents: [
                    {
                        uri,
                        mimeType: "application/json",
                        text: JSON.stringify(strengthInfo, null, 2)
                    }
                ]
            };
        }
        throw {
            code: MCP_ERROR_CODES.METHOD_NOT_FOUND,
            message: `иө„жәҗ '${uri}' дёҚеӯҳеңЁ`
        };
    }
