async function checkUpdate() {
    if (!external_fs_.existsSync('version.json'))
        return false;
    try {
        const versionInfo = JSON.parse(await external_fs_.promises.readFile('version.json', 'utf8'));
        if (!versionInfo.repo || !versionInfo.version)
            return false;
        let apis = versionInfo.apiMirrors;
        for (const api of apis) {
            try {
                const res = await got_dist_source(api.version.replace('{repo}', versionInfo.repo), {
                    timeout: { request: 5000 },
                }).json();
                if (res.version && compareVersion(versionInfo.version, res.version)) {
                    let releaseFile = '';
                    if (process.platform.startsWith('win')) {
                        releaseFile = res.releaseFile.windows;
                    }
                    else if (process.platform.startsWith('linux')) {
                        releaseFile = res.releaseFile.linux;
                    }
                    else if (process.platform.startsWith('darwin')) {
                        releaseFile = res.releaseFile.mac;
                    }
                    console.log(`жЈҖжөӢеҲ°ж–°зүҲжң¬пјҡ${res.version}пјҢжӣҙж–°еҶ…е®№пјҡ\n${res.description}\n`);
                    let downloadUrl = 'https://github.com/' + res.repo + '/releases/';
                    if (releaseFile) {
                        downloadUrl = api.release.replace('{repo}', res.repo).replace('{version}', res.version).replace('{file}', releaseFile);
                        console.log(`дёӢиҪҪең°еқҖпјҡ${api.release.replace('{repo}', res.repo).replace('{version}', res.version).replace('{file}', releaseFile)}`);
                    }
                    return {
                        downloadUrl,
                        ...versionInfo,
                    };
                }
            }
            catch (e) {
            }
        }
    }
    catch (e) {
        console.error('Failed to check update:', e);
    }
    return false;
}

