        if (!updateInfo)
            return;
        if (MainConfig.value.hideWebUpdateNotification)
            return; // дёҚеңЁжҺ§еҲ¶еҸ°жҳҫзӨәжӣҙж–°йҖҡзҹҘ
        SiteNotificationService.instance.addNotification({
            severity: 'secondary',
            icon: 'pi pi-download',
            title: `еҸ‘зҺ°ж–°зүҲжң¬ ${updateInfo.version}`,
            message: updateInfo.description ?? 'иҜ·еүҚеҫҖGitHubжҹҘзңӢжӣҙж–°еҶ…е®№гҖӮ',
            url: updateInfo.downloadUrl,
            urlLabel: 'дёӢиҪҪ',
            sticky: true,
            ignoreId: 'update-notification-' + updateInfo.version,
        });
